-- sqlcl_snapshot src/database/myapp/tables/coaches.sql:null:03544dedcdcf7fac241f1e6d3a0cea995e696366:create

create table coaches (
    coach_id      number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    team_id       number not null enable,
    first_name    varchar2(60 byte) not null enable,
    last_name     varchar2(60 byte) not null enable,
    coach_role    varchar2(40 byte) not null enable,
    hire_date     date not null enable,
    annual_salary number(12, 2),
    active_flag   char(1 byte) default 'Y' not null enable
);

alter table coaches
    add constraint coaches_active_ck
        check ( active_flag in ( 'Y', 'N' ) ) enable;

alter table coaches
    add constraint coaches_pk primary key ( coach_id )
        using index enable;

alter table coaches
    add constraint coaches_role_ck
        check ( coach_role in ( 'HEAD_COACH', 'ASSISTANT_COACH', 'SKILLS_COACH', 'MEDICAL_STAFF' ) ) enable;

